pub fn decodeEvent(reader: *std.Io.Reader) DecodeError!global_events.Event {
    const code = (try reader.peek(1))[0] & 0x7f;
    return switch (code) {
        0 => .{ .RandrScreenChangeNotify = try ScreenChangeNotifyEvent.decode(reader) },
        1 => .{ .RandrNotify = try NotifyEvent.decode(reader) },
        else => blk: {
            const packet = try reader.take(32);
            var raw: [32]u8 = undefined;
            @memcpy(raw[0..], packet);
            break :blk .{ .Unknown = .{
                .code = packet[0] & 0x7f,
                .sequence = std.mem.readInt(u16, packet[2..4], .native),
                .raw = raw,
            } };
        },
    };
}

